import React, { useState, useEffect } from 'react';
import './About.css';

interface Experience {
  company: string;
  position: string;
  duration: string;
  description: string;
}

interface Education {
  institution: string;
  degree: string;
  duration: string;
  description: string;
}

interface AboutData {
  name: string;
  title: string;
  bio: string;
  email: string;
  phone: string;
  location: string;
  skills: string[];
  experience: Experience[];
  education: Education[];
}

const About: React.FC = () => {
  const [aboutData, setAboutData] = useState<AboutData>({
    name: 'Hello, I am Jatin',
    title: '',
    bio: 'I am a passionate full-stack developer with expertise in modern web technologies. With a strong foundation in both frontend and backend development, I create scalable and user-friendly applications. My journey in tech started with a curiosity about how things work on the internet, and has evolved into a career focused on building innovative solutions.',
    email: 'your.email@example.com',
    phone: '08168954304',
    location: ', Country',
    skills: ['React', 'TypeScript', 'Node.js', 'MongoDB', 'Express.js', 'CSS', 'HTML', 'JavaScript', 'Git', 'REST APIs', 'GraphQL', 'Redux'],
    experience: [
      {
        company: 'Tech Company Inc.',
        position: 'Senior Full Stack Developer',
        duration: '2022 - Present',
        description: 'Lead development of enterprise web applications using React and Node.js. Mentored junior developers and implemented best practices for code quality and performance.'
      },
      {
        company: 'Digital Agency',
        position: 'Full Stack Developer',
        duration: '2020 - 2022',
        description: 'Developed and maintained multiple client websites and web applications. Worked with cross-functional teams to deliver projects on time and within budget.'
      },
      {
        company: 'StartUp Hub',
        position: 'Junior Developer',
        duration: '2019 - 2020',
        description: 'Assisted in the development of web applications and gained experience in modern JavaScript frameworks and database management.'
      }
    ],
    education: [
      {
        institution: 'University of Technology',
        degree: 'Bachelor of Science in Computer Science',
        duration: '2015 - 2019',
        description: 'Graduated with honors. Focused on software engineering, algorithms, and data structures. Participated in coding competitions and hackathons.'
      },
      {
        institution: 'Tech Bootcamp',
        degree: 'Full Stack Web Development',
        duration: '2018',
        description: 'Intensive 12-week program covering modern web development technologies including React, Node.js, and MongoDB.'
      }
    ]
  });

  useEffect(() => {
    const fetchAboutData = async () => {
      try {
        const response = await fetch('/api/about');
        if (response.ok) {
          const data = await response.json();
          if (data) {
            setAboutData(data);
          }
        }
      } catch (error) {
        console.log('Using default data, API not available');
      }
    };

    fetchAboutData();
  }, []);

  return (
    <div className="about">
      <div className="container">
        <h1 className="page-title">About Me</h1>

        <section className="about-intro">
          <div className="intro-content">
            <h2>{aboutData.name}</h2>
            <h3>{aboutData.title}</h3>
            <p className="intro-bio">{aboutData.bio}</p>
          </div>
        </section>

        <section className="contact-info">
          <h2>Contact Information</h2>
          <div className="contact-grid">
            <div className="contact-item">
              <strong>Email:</strong> {aboutData.email}
            </div>
            <div className="contact-item">
              <strong>Phone:</strong> {aboutData.phone}
            </div>
            <div className="contact-item">
              <strong>Location:</strong> {aboutData.location}
            </div>
          </div>
        </section>

        <section className="skills-section">
          <h2>Technical Skills</h2>
          <div className="skills-grid">
            {aboutData.skills.map((skill, index) => (
              <div key={index} className="skill-card">
                <span className="skill-name">{skill}</span>
              </div>
            ))}
          </div>
        </section>

        <section className="experience-section">
          <h2>Work Experience</h2>
          <div className="timeline">
            {aboutData.experience.map((exp, index) => (
              <div key={index} className="timeline-item">
                <div className="timeline-content">
                  <div className="timeline-header">
                    <h3>{exp.position}</h3>
                    <h4>{exp.company}</h4>
                    <span className="timeline-date">{exp.duration}</span>
                  </div>
                  <p>{exp.description}</p>
                </div>
              </div>
            ))}
          </div>
        </section>

        <section className="education-section">
          <h2>Education</h2>
          <div className="timeline">
            {aboutData.education.map((edu, index) => (
              <div key={index} className="timeline-item">
                <div className="timeline-content">
                  <div className="timeline-header">
                    <h3>{edu.degree}</h3>
                    <h4>{edu.institution}</h4>
                    <span className="timeline-date">{edu.duration}</span>
                  </div>
                  <p>{edu.description}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
};

export default About;
